div.dev-wrapper > h3 > span{float:right;font-size:.6em;}
div.covid-block{border-radius:10px;margin:10px;}
div.covid-block > .block-content{border-radius:0px 0px 10px 10px;}
html[data-theme="light"] div.covid-block{box-shadow:3px 3px 5px 2px lightgray}
html[data-theme="light"] div.dev-wrapper{background-color:#efefef;border-radius:10px;box-shadow:3px 3px 5px 2px lightgray;margin:10px;padding:10px 10px 0px;}
html[data-theme="light"] div.covid-block > div.heading {border:none;}
html[data-theme="light"] div.dev-wrapper > .accordion-section > .accordion-section-content{border-radius:10px;}
html[data-theme="blue"] div.dev-wrapper > .accordion-section *{background-color:transparent;}
html[data-theme="dark"] div.dev-wrapper > .accordion-section *{background-color:transparent;}
html[data-theme="dark"] div.covid-block > div.heading {background-color:transparent;}
html[data-theme="blue"] div.dev-wrapper,html[data-theme="dark"] div.dev-wrapper{border:solid;border-color:white;border-radius:10px;border-width:1px;margin:10px;padding:10px 10px 0px;}
